class Solution:
    def solve(self, arr: List[int])-> bool:
        for i in range(1, len(arr)):
            if arr[i] < arr[i - 1]:
                return False
            key = arr[i]
            j = i-1
            while j >= 0 and arr[j] > key:
                arr[j + 1] = arr[j]
                j -= 1
            arr[j + 1] = key
        return True

